import React, { useState, useEffect, useRef } from 'react';
import logo from './logo.svg';
import './App.css';

function App() {
  const [displayText, setDisplayText] = useState('');
  const terminalRef = useRef(null);
  const [cursorVisible, setCursorVisible] = useState(true);

  useEffect(() => {
    const terminalOutputs = [
      'Windows PowerShell',
      'Copyright (C) Microsoft Corporation. All rights reserved.',
      '',
      'PS C:\\users\\Admin> ',
    ];

    const typingTexts = [
      'My',
      'Name',
      'is',
      'Nathaniel',
      'But People Call me Nate',
    ];

    let currentTextIndex = 0;
    let currentWordIndex = 0;

    const typeText = () => {
      if (currentTextIndex < typingTexts.length) {
        const currentWord = typingTexts[currentTextIndex];
        const textWithCursor = terminalOutputs[3] + (currentWordIndex > 0 ? ' ' : '') + currentWord + (cursorVisible ? '|' : '');
        setDisplayText(terminalOutputs.slice(0, 3).join('\n') + '\n' + textWithCursor);

        if (currentWordIndex < currentWord.length) {
          currentWordIndex++;
        } else {
          currentTextIndex++;
          currentWordIndex = 0;
          setTimeout(typeText, 1000); // Delay between words
          return;
        }
      } else {
        setTimeout(() => {
          setDisplayText(terminalOutputs.slice(0, 3).join('\n') + '\n' + terminalOutputs[3]);
          setTimeout(() => {
            const nateText = terminalOutputs[3] + ' But People Call me Nate';
            setDisplayText(terminalOutputs.slice(0, 3).join('\n') + '\n' + nateText);
          }, 2000); // Delay before displaying "But People Call me Nate"
        }, 1000); // Delay after typing all words
        return;
      }

      terminalRef.current.scrollTop = terminalRef.current.scrollHeight;

      setTimeout(typeText, 100); // Delay between each letter
    };

    setDisplayText(terminalOutputs.join('\n'));

    terminalRef.current.scrollTop = terminalRef.current.scrollHeight;

    const cursorInterval = setInterval(() => {
      setCursorVisible((prevVisible) => !prevVisible);
    }, 500);

    setTimeout(typeText, 2000); // Delay before typing starts

    return () => {
      clearInterval(cursorInterval);
    };
  }, []);

  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <div className="terminal" ref={terminalRef}>
          <pre>{displayText}</pre>
          {cursorVisible && <span className="cursor">|</span>}
        </div>
      </header>
    </div>
  );
}

export default App;
